import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("Claim Office - quote (premium)", () => {
  // Fee-only baseline
  it.todo("should charge 5 G (fee only) for an empty item list");

  // Single main item base premiums + fee
  it.todo("should quote a single sword at 105 G (100 base + 5 fee)");
  it.todo("should quote a single amulet at 65 G (60 base + 5 fee)");
  it.todo("should quote a single staff at 85 G (80 base + 5 fee)");
  it.todo("should quote a single potion at 45 G (40 base + 5 fee)");

  // Multiple main items sum their base premiums
  it.todo("should sum base premiums for a sword and an amulet to 165 G (160 base + 5 fee)");

  // Component base premiums
  it.todo("should quote a single rune at 30 G (25 base + 5 fee)");
  it.todo("should quote 2 runes at 55 G (50 base + 5 fee)");

  // Building block of 3 alike components
  it.todo("should quote 3 runes as a block at 65 G (60 base + 5 fee)");
  it.todo("should quote 4 runes at 105 G (no block, 100 base + 5 fee)");
  it.todo("should quote 7 runes at 180 G (175 base + 5 fee)");

  // Alike = same type only
  it.todo("should not form a block for 2 runes + 1 moonstone (75 base + 5 fee = 80 G)");
  it.todo("should form two separate blocks for 3 runes + 3 moonstones (120 base + 5 fee = 125 G)");

  // Item-specific modifiers
  it.todo("should add 50% curse surcharge to the cursed item's base premium");
  it.todo("should add 30% high-enchantment surcharge for enchantment >= 5");
  it.todo("should not add high-enchantment surcharge for enchantment 4");
  it.todo("should apply both curse and high-enchantment surcharges to a cursed enchantment-5 item");

  // Modifier scope on multi-item policies
  it.todo("should apply the curse surcharge only to the cursed item, not the whole policy (cursed sword + plain amulet = 210 base before fee)");

  // Policy-wide modifiers
  it.todo("should apply 20% loyalty discount for a customer with exactly 2 years");
  it.todo("should apply 10% first-insurance surcharge to the policy base premium");
  it.todo("should apply 15% follow-up discount on quotes after the customer's first quote");

  // Rounding up in MHPCO's favor
  it.todo("should round the final premium up (197.5 G becomes 198 G)");

  // Integration examples
  it.todo("should quote a newcomer's cursed steel sword (enchantment 3) at 165 G");
  it.todo("should quote a 3-year customer's second-quote cursed steel sword (enchantment 7) at 160 G");

  // Error case
  it.todo("should reject a quote containing an item with an unknown type");
});

describe("Claim Office - claim (payout)", () => {
  // Standard reimbursement minus deductible
  it.todo("should pay full damage minus 100 G deductible for a regular item (sword, enchantment 3, damage 500 -> 400)");
  it.todo("should pay full damage minus 100 G deductible for a component (rune, damage 200 -> 100)");

  // High-enchantment clause
  it.todo("should reimburse 50% then deduct 100 G for enchantment >= 8 (steel sword, enchantment 9, damage 1000 -> 400)");

  // Dragon-material clause
  it.todo("should fully reimburse then deduct 100 G for dragon material (dragon sword, enchantment 5, damage 800 -> 700)");

  // Conflict: 50% rule wins over dragon
  it.todo("should apply the 50% rule (not full) when both high-enchantment >= 8 and dragon apply (dragon sword, enchantment 9, damage 1000 -> 400)");

  // Threshold confirmation
  it.todo("should treat enchantment exactly 8 as high-enchantment (dragon sword, enchantment 8, damage 1000 -> 400)");

  // Deductible per damage event
  it.todo("should apply the 100 G deductible once per damaged item (sword 500 + amulet 300 -> 600)");

  // Cap behaviour
  it.todo("should cap total payout at twice the insurance sum");
  it.todo("should share the cap across successive claims and reduce payout to the remaining cap");

  // Rounding down in MHPCO's favor
  it.todo("should round the final payout down (350.5 G becomes 350 G)");

  // Error cases
  it.todo("should reject a claim whose damage entry references an item not in the policy");
  it.todo("should reject a claim with more damage entries of a type than the policy covers");
  it.todo("should reject a claim with a negative damage amount");
});
